import React, { useState } from 'react'
import { useNavigate } from 'react-router-dom'
import { useSelector,useDispatch } from 'react-redux'
import { addDetails,showDetails } from './redux';
import './css_comp/trainsearching.css';

export default function Trainsearching() {
    const dispatch=useDispatch();
    const navigate = useNavigate()
    const train = useSelector((state) => state.var.train)
    const stations = (train) => {
        const arr = new Set()
        train.map((item) => {
            item.stations.map((i) => {
                arr.add(i)
            })
        })
        return [...arr]
    }


    const [from, setFrom] = useState('')
    const [to, setTo] = useState('')
    const [date, setDate] = useState('')

    const [result, setResult] = useState(stations(train))

    const searchresult = result.filter((item) => item.toLowerCase().includes(from.toLowerCase()))
    const searchresult2 = result.filter((item) => item.toLowerCase().includes(to.toLowerCase()))
    const [classs, setClass] = useState(null)
    console.log("length: ", searchresult.length)
    const [show1, setShow1] = useState(true)
    const [show2, setShow2] = useState(true)
    const handlechange = (e) => {

    }
    const journey_details=useSelector((state)=>state.var.journey_inf)
    const passinfo = (e) => {
        e.preventDefault()
        if(from && to && date && classs ){
            const journey_info = {
                from: from,
                to: to,
                date: date,
                class: classs
            }
            dispatch(addDetails(journey_info))
            navigate('/results')

            alert('value inserted')
        }else{
            alert('not inserted')
        }

        

    }   
    const s=useSelector((state)=>state.var.journey_inf)
    console.log("details:",s)

    return (
        <>
        {/* <form action="" onSubmit={(e) => passinfo(e)}>
            <div className='searching-container' >
                <div className='input-holder'>
                    <div style={{ display: 'flex', justifyContent: 'space-around', alignItems: 'center' }}>
                        <div>
                            <label htmlFor="">From</label> <br />
                            <input type="text" value={from} onChange={(e) => { setFrom(e.target.value); setShow1(true); }} />
                            {from && show1 ? <div style={{ minWidth: 150, backgroundColor: 'aliceblue', zIndex: 1, position: 'absolute' }} >
                                {
                                    searchresult.slice(0, 4).map((item) => (
                                        <li style={{ cursor: 'pointer' }} onClick={() => { setShow1(false); setFrom(item) }}>{item}</li>
                                    ))
                                }</div> : null}


                        </div>
                        <div>
                            <label htmlFor="">To</label><br />
                            <input type="text" value={to} onChange={(e) => { setTo(e.target.value); setShow2(true); }} />
                            {to && show2 ? <div style={{ minWidth: 150, backgroundColor: 'aliceblue', zIndex: 1, position: 'absolute' }} >
                                {
                                    searchresult2.slice(0, 4).map((item) => (
                                        <li style={{ cursor: 'pointer' }} onClick={() => { setShow2(false); setTo(item) }}>{item}</li>
                                    ))
                                }</div> : null}

                        </div>
                    </div>

                    <div style={{ marginTop: 10, display: 'flex', justifyContent: 'space-around', alignItems: 'center' }}>
                        <div>
                            <label htmlFor="">Date</label> <br />
                            <input type="date" name="" id="" value={date} onChange={(e) => setDate(e.target.value)} />
                        </div>
                        <div>
                            <label htmlFor="">To</label><br />
                            <select id="" value={classs} onChange={(e) => setClass(e.target.value)} >
                                <option value="">Choose one</option>
                                <option value="Snigdha">Snigdha</option>
                                <option value="AC-B">AC-B</option>
                                <option value="Shovon">Shovon</option>
                                <option value="AC-S">AC-S</option>
                            </select>
                        </div>
                    </div>
                    {from && to && date && classs ? <div style={{ marginTop: 80, display: 'flex', justifyContent: 'center', alignItems: 'center', width: 'auto' }}><button style={{ minWidth: 50, minHeight: 20, border: '2px solid gray', padding: 5, borderRadius: 10, cursor: 'pointer' }} >Search</button></div> : <div style={{ marginTop: 80, display: 'flex', justifyContent: 'center', alignItems: 'center', width: 'auto' }}><button style={{ minWidth: 50, minHeight: 20, border: '2px solid gray', padding: 5, borderRadius: 10, cursor: 'not-allowed' }} >Search</button></div>}

                </div>
            </div>



        </form>
 */}


        </>
    )
}
